#include <vector>
#include <algorithm>
#include <unordered_set>

using namespace std;

struct DSU {
    vector<int> parent, rank;
    DSU(int n) : parent(n), rank(n) {
        for (int i = 0; i < n; ++i) {
            parent[i] = i;
            rank[i] = 1;
        }
    }
    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }
    void union_(int x, int y) {
        int xroot = find(x);
        int yroot = find(y);
        if (xroot == yroot) return;
        if (rank[xroot] < rank[yroot]) {
            parent[xroot] = yroot;
        } else {
            parent[yroot] = xroot;
            if (rank[xroot] == rank[yroot]) {
                rank[xroot]++;
            }
        }
    }
};

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    sort(edges.begin(), edges.end(), [](vector<long long> a, vector<long long> b) {
        return a[2] < b[2];
    });
    long long low = 0, high = 0;
    for (auto& e : edges) {
        high = max(high, e[2]);
    }
    long long answer = high;
    while (low <= high) {
        long long mid = (low + high) / 2;
        DSU dsu(n);
        for (auto& e : edges) {
            if (e[2] <= mid) {
                dsu.union_(e[0], e[1]);
            }
        }
        unordered_set<int> roots;
        for (int i = 0; i < n; ++i) {
            roots.insert(dsu.find(i));
        }
        int cnt = roots.size();
        if (cnt <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return answer;
}

